<?php
session_start();
include 'config.php';

if (!isset($_SESSION['doctor_id'])) {
    header('location:Doctor_Login.php');
    exit();
}

$doctor_id = (int)$_SESSION['doctor_id'];

$doctor_name = 'Doctor';
$select = mysqli_query($conn, "SELECT DoctorName FROM add_doctor WHERE id = '$doctor_id' LIMIT 1");
if ($select && ($fetch = mysqli_fetch_assoc($select))) {
    $doctor_name = $fetch['DoctorName'];
}

$sql = "SELECT Name, Email, Phone, appointment_Date, appointment_Time, patient_type, patient_report, status FROM user_appointments WHERE doctor_id = ? ORDER BY appointment_Date DESC";
$stmt = $conn->prepare($sql);
$stmt->bind_param('i', $doctor_id);
$stmt->execute();
$result = $stmt->get_result();
?>
